noncompliant:
class BadClass { // Noncompliant - mixing public and private data
public:
    int publicData;
    void setPrivateData(int value) { privateData = value; }
private:
    int privateData; // Mixed with public data
};

compliant:
// Option 1: All data private (proper encapsulation)
class GoodClass {
private:
    int data1;
    int data2;
public:
    void setData1(int value) { data1 = value; }
    int getData1() const { return data1; }
};

// Option 2: All data public (data structure)
struct DataStruct {
public:
    int data1;
    int data2;
};
